            ['topic'=>'Cryptography and Steganography','question_type'=>'mcq_4','question_text'=>'What is steganography?','option_a'=>'Encryption of messages','option_b'=>'Hiding messages within other data','option_c'=>'Compressing files','option_d'=>'Hashing passwords','correct_answer'=>'Hiding messages within other data','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'mcq_4','question_text'=>'Which of the following is a symmetric encryption algorithm?','option_a'=>'RSA','option_b'=>'DES','option_c'=>'ECC','option_d'=>'ElGamal','correct_answer'=>'DES','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'mcq_4','question_text'=>'What is LSB steganography?','option_a'=>'Least Significant Bit manipulation to hide data','option_b'=>'Largest Steganographic Bandwidth','option_c'=>'Linked Steganographic Block','option_d'=>'Linear Signal Bandwidth','correct_answer'=>'Least Significant Bit manipulation to hide data','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'mcq_4','question_text'=>'What is a Caesar cipher?','option_a'=>'A hash function','option_b'=>'A substitution cipher shifting letters by a fixed number','option_c'=>'A block cipher','option_d'=>'An asymmetric algorithm','correct_answer'=>'A substitution cipher shifting letters by a fixed number','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'mcq_4','question_text'=>'Which algorithm is commonly used for public-key cryptography?','option_a'=>'AES','option_b'=>'MD5','option_c'=>'RSA','option_d'=>'SHA-256','correct_answer'=>'RSA','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'mcq_2','question_text'=>'Public key and private key are the same in asymmetric encryption.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'False','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'mcq_2','question_text'=>'SHA-256 is an encryption algorithm.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'False','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'mcq_2','question_text'=>'AES-256 is more secure than AES-128.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'True','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'short_question','question_text'=>'What is the difference between cryptography and steganography?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'Cryptography scrambles a message so it cannot be read without a key (its existence is known). Steganography hides the message inside another medium (image, audio) so the existence of the message is hidden.','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'short_question','question_text'=>'What is a digital watermark?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'A digital watermark is hidden information embedded into digital media to identify ownership, verify authenticity, or track unauthorized copying using steganographic techniques.','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'short_question','question_text'=>'What is a hash collision?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'A hash collision occurs when two different inputs produce the same hash output. Strong hash functions (SHA-256) minimize collision probability; weak ones (MD5) are vulnerable to collision attacks.','difficulty_level'=>'hard','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'long_question','question_text'=>'Explain the RSA algorithm and how it achieves security.','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'RSA: choose two large primes p and q, compute n=p×q, find φ(n)=(p-1)(q-1), select public exponent e (coprime to φ(n)), compute private key d where d×e≡1(mod φ(n)). Encryption: ciphertext = m^e mod n. Decryption: m = c^d mod n. Security relies on the computational difficulty of factoring the product of two large primes. RSA 2048-bit is infeasible to break with current computing.','difficulty_level'=>'hard','marks'=>1.00],
            ['topic'=>'Cryptography and Steganography','question_type'=>'long_question','question_text'=>'Discuss the applications and ethical concerns of steganography.','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'Applications: digital watermarking, covert communication, copyright protection, military intelligence, and embedding patient data in medical images. Ethical concerns: criminals use steganography to avoid surveillance. Steganalysis tools detect hidden data. Balancing security, privacy, and legitimate use is a major ongoing ethical and regulatory challenge.','difficulty_level'=>'medium','marks'=>1.00],

            // =========================================================
            // UI AND UX (Q147–Q159) 12
            // =========================================================
            ['topic'=>'UI and UX','question_type'=>'mcq_4','question_text'=>'What does UX stand for?','option_a'=>'User Extension','option_b'=>'User Experience','option_c'=>'Unified Exchange','option_d'=>'User Examination','correct_answer'=>'User Experience','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'UI and UX','question_type'=>'mcq_4','question_text'=>'Which principle ensures that important elements stand out visually?','option_a'=>'Proximity','option_b'=>'Hierarchy','option_c'=>'Alignment','option_d'=>'Repetition','correct_answer'=>'Hierarchy','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'UI and UX','question_type'=>'mcq_4','question_text'=>'What is a persona in UX design?','option_a'=>'A real user being tested','option_b'=>'A fictional character representing a user segment','option_c'=>'A UI prototype','option_d'=>'A testing tool','correct_answer'=>'A fictional character representing a user segment','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'UI and UX','question_type'=>'mcq_4','question_text'=>'What is a prototype in UI design?','option_a'=>'A final product','option_b'=>'An interactive simulation of the final design','option_c'=>'Source code','option_d'=>'A user manual','correct_answer'=>'An interactive simulation of the final design','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'UI and UX','question_type'=>'mcq_2','question_text'=>'UI and UX design are the same discipline.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'False','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'UI and UX','question_type'=>'mcq_2','question_text'=>'Heuristic evaluation involves real users testing the system.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'False','difficulty_level'=>'hard','marks'=>1.00],
            ['topic'=>'UI and UX','question_type'=>'mcq_2','question_text'=>'The "fold" in web design refers to the visible area without scrolling.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'True','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'UI and UX','question_type'=>'short_question','question_text'=>'What is a wireframe in UX design?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'A wireframe is a low-fidelity schematic representation of a digital interface showing structure and layout without visual design details, used for planning and stakeholder feedback.','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'UI and UX','question_type'=>'short_question','question_text'=>'What is Fitts\' Law and how does it apply to UI design?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'Fitts\' Law states that the time to reach a target depends on its size and distance. In UI design, important buttons should be large and easily reachable to reduce interaction time and errors.','difficulty_level'=>'hard','marks'=>1.00],
            ['topic'=>'UI and UX','question_type'=>'short_question','question_text'=>'What is a user journey map?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'A user journey map visualizes the steps a user takes to achieve a goal when interacting with a product, highlighting touchpoints, emotions, pain points, and opportunities for improvement.','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'UI and UX','question_type'=>'long_question','question_text'=>'Explain the UX design process from research to final design.','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'UX process: (1) Research — user interviews, surveys, personas; (2) Define — journey maps, problem statements; (3) Ideate — brainstorming, design thinking; (4) Prototype — wireframes and interactive mockups (Figma); (5) Test — usability testing, A/B testing; (6) Implement — developer collaboration; (7) Evaluate — analytics and iteration. The process is iterative, with insights looping back to earlier phases.','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'UI and UX','question_type'=>'long_question','question_text'=>'Discuss the importance of accessibility in UI/UX design.','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'Accessibility ensures products are usable by people with disabilities. WCAG 2.1 defines levels A, AA, AAA. Key practices: color contrast (4.5:1 ratio), alt text, keyboard navigation, ARIA roles, video captions. The curb-cut effect shows accessibility improvements benefit all users. It is legally required in many countries (ADA, EN 301 549) and expands market reach.','difficulty_level'=>'hard','marks'=>1.00],

            // =========================================================
            // IOT AND FOG COMPUTING (Q160–Q169) 9
            // =========================================================
            ['topic'=>'IoT and Fog Computing','question_type'=>'mcq_4','question_text'=>'What is fog computing?','option_a'=>'Computing in outer space','option_b'=>'Edge computing closer to IoT devices','option_c'=>'Cloud computing for weather data','option_d'=>'A type of network protocol','correct_answer'=>'Edge computing closer to IoT devices','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'IoT and Fog Computing','question_type'=>'mcq_4','question_text'=>'Which protocol is commonly used in IoT communications?','option_a'=>'FTP','option_b'=>'HTTP','option_c'=>'MQTT','option_d'=>'SMTP','correct_answer'=>'MQTT','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'IoT and Fog Computing','question_type'=>'mcq_4','question_text'=>'What is a sensor node in IoT?','option_a'=>'A cloud server','option_b'=>'A device that collects and transmits environmental data','option_c'=>'A network router','option_d'=>'An application server','correct_answer'=>'A device that collects and transmits environmental data','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'IoT and Fog Computing','question_type'=>'mcq_2','question_text'=>'Fog computing reduces latency compared to cloud computing for IoT.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'True','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'IoT and Fog Computing','question_type'=>'mcq_2','question_text'=>'IoT devices always require a constant internet connection to function.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'False','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'IoT and Fog Computing','question_type'=>'short_question','question_text'=>'What is the difference between fog computing and edge computing?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'Edge computing processes data directly on end devices (sensors, cameras). Fog computing is an intermediate layer between edge devices and the cloud, providing a gateway with more processing power than edge but less than full cloud.','difficulty_level'=>'hard','marks'=>1.00],
            ['topic'=>'IoT and Fog Computing','question_type'=>'short_question','question_text'=>'What are the main security challenges in IoT?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'IoT security challenges include weak default credentials, lack of encryption, infrequent firmware updates, large attack surface from millions of devices, limited computational power for security, and physical vulnerabilities (e.g., Mirai botnet exploited default passwords).','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'IoT and Fog Computing','question_type'=>'long_question','question_text'=>'Discuss the architecture of an IoT system and the role of fog computing.','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'IoT system layers: (1) Perception — sensors/actuators collect data; (2) Network — data via Wi-Fi, Zigbee, LoRa, cellular; (3) Application — data processed and presented. Fog computing adds an intermediate layer providing local computation, storage, and communication. Benefits: reduced latency, bandwidth conservation, improved privacy, offline operation. Applications: smart cities, industrial IoT, healthcare. Challenges: managing distributed nodes, security, standardization.','difficulty_level'=>'hard','marks'=>1.00],
            ['topic'=>'IoT and Fog Computing','question_type'=>'long_question','question_text'=>'Explain how fog computing supports smart city applications.','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'Smart cities use IoT sensors for traffic, lighting, water, waste, and safety systems. Fog computing enables: real-time traffic signal control at intersections, instant emergency response alerts, smart grid demand-response, real-time video surveillance analytics, and optimized garbage truck routing. Benefits: sub-millisecond response, reduced network congestion, higher reliability. Challenges: coordinating distributed infrastructure and ensuring vendor interoperability.','difficulty_level'=>'medium','marks'=>1.00],

