            ['topic'=>'Human Computer Interaction','question_type'=>'mcq_4','question_text'=>'What does HCI stand for?','option_a'=>'High Computer Interface','option_b'=>'Human Computer Interaction','option_c'=>'Hardware Control Integration','option_d'=>'Human Command Interpreter','correct_answer'=>'Human Computer Interaction','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'mcq_4','question_text'=>"Which of Nielsen's heuristics says users should not have to remember information?",'option_a'=>'Visibility of system status','option_b'=>'Recognition rather than recall','option_c'=>'Error prevention','option_d'=>'Aesthetic design','correct_answer'=>'Recognition rather than recall','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'mcq_4','question_text'=>'What is a think-aloud protocol?','option_a'=>'A coding standard','option_b'=>'Users verbalize their thoughts while performing tasks','option_c'=>'A design pattern','option_d'=>'An encryption method','correct_answer'=>'Users verbalize their thoughts while performing tasks','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'mcq_4','question_text'=>'Which research method in HCI involves observing users in their natural environment?','option_a'=>'Surveys','option_b'=>'Ethnographic study','option_c'=>'A/B testing','option_d'=>'Heuristic evaluation','correct_answer'=>'Ethnographic study','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'mcq_2','question_text'=>'HCI only focuses on the visual design of interfaces.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'False','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'mcq_2','question_text'=>'Mental models in HCI refer to users\' internal understanding of a system.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'True','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'mcq_2','question_text'=>'Cognitive load refers to the mental effort required to use an interface.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'True','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'mcq_2','question_text'=>'Consistency in UI design helps users transfer knowledge between different parts of a system.','option_a'=>'True','option_b'=>'False','option_c'=>null,'option_d'=>null,'correct_answer'=>'True','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'short_question','question_text'=>'What is usability in HCI?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'Usability measures how effectively, efficiently, and satisfactorily users achieve goals with a system. ISO 9241 defines it through learnability, efficiency, memorability, error frequency, and satisfaction.','difficulty_level'=>'easy','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'short_question','question_text'=>'What is affordance in interface design?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'Affordance is the perceived property of an object that suggests how it should be used. A button that looks raised affords clicking; a slider affords dragging. Good design uses clear affordances to guide interaction intuitively.','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'short_question','question_text'=>'What is GOMS in HCI?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'GOMS (Goals, Operators, Methods, Selection rules) is a cognitive model that predicts user performance by modeling goals, primitive actions, methods to achieve goals, and rules for selecting among competing methods.','difficulty_level'=>'hard','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'short_question','question_text'=>'What is the difference between learnability and memorability in usability?','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'Learnability measures how easily new users accomplish tasks on first use. Memorability measures how well users can reuse the system after a period of not using it. Both are usability dimensions defined by Nielsen.','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'long_question','question_text'=>"Discuss Nielsen's 10 Usability Heuristics and their importance.",'option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>"Nielsen's 10 Heuristics: (1) Visibility of system status; (2) Match between system and real world; (3) User control and freedom; (4) Consistency and standards; (5) Error prevention; (6) Recognition rather than recall; (7) Flexibility and efficiency; (8) Aesthetic and minimalist design; (9) Help users recognize and recover from errors; (10) Help and documentation. These guide expert heuristic evaluation, enabling early, low-cost identification of usability issues.",'difficulty_level'=>'hard','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'long_question','question_text'=>'Explain the evolution of human-computer interaction from command-line to natural interfaces.','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'HCI evolution: (1) CLI — text commands, steep learning curve (UNIX, DOS); (2) GUI — windows, icons, mouse democratized computing (Macintosh, Windows); (3) Touch — direct manipulation on smartphones; (4) Voice — natural language assistants (Siri, Alexa); (5) Gesture/AR/VR — motion sensing and immersive interfaces; (6) Brain-Computer Interfaces — emerging neural control. Each evolution reduced technical barriers and expanded access.','difficulty_level'=>'medium','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'long_question','question_text'=>'Discuss the role of HCI in the design of medical devices and systems.','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'Poor HCI in healthcare causes medication errors and device failures. Applications: EHR usability reduces physician burnout, infusion pumps require clear displays and error prevention, telemedicine must be usable by elderly users, alert systems must avoid alert fatigue. HCI principles: error prevention, minimalist design, consistent feedback. FDA requires human factors engineering in medical device approval.','difficulty_level'=>'hard','marks'=>1.00],
            ['topic'=>'Human Computer Interaction','question_type'=>'long_question','question_text'=>'Explain multimodal interaction and its advantages in modern HCI.','option_a'=>null,'option_b'=>null,'option_c'=>null,'option_d'=>null,'correct_answer'=>'Multimodal interaction combines multiple input/output channels — speech, touch, gesture, gaze, haptic feedback. Examples: speech + touch on smartphones, gesture + voice in AR/VR, eye-gaze for accessibility. Advantages: flexibility, efficiency, error reduction, accessibility, and natural interaction mimicking human communication. Challenges: integrating modalities, handling ambiguity, maintaining context. Central to smart speakers, autonomous vehicles, and XR environments.','difficulty_level'=>'hard','marks'=>1.00],
